import{_ as a,o,c as s,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"67. Compassionate Leave","description":"","frontmatter":{"title":"67. Compassionate Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","compassionate-leave"]},"headers":[],"relativePath":"ebas/allied-health/leave/67-compassionate-leave.md","filePath":"ebas/allied-health/leave/67-compassionate-leave.md"}'),n={name:"ebas/allied-health/leave/67-compassionate-leave.md"};function i(r,e,l,p,c,m){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="_67-compassionate-leave" tabindex="-1">67. Compassionate Leave <a class="header-anchor" href="#_67-compassionate-leave" aria-label="Permalink to &quot;67. Compassionate Leave&quot;">​</a></h1><p><strong>67.1</strong> When compassionate leave is available Compassionate leave is available under this clause 67 to an Employee for each occasion (a “permissible occasion”) when:</p><p><strong>(a)</strong> a member of the Employee’s Immediate Family or household:</p><p><strong>(i)</strong> contracts or develops a personal illness or sustains a personal injury that poses a serious threat to their life; or</p><p><strong>(ii)</strong> dies;</p><p><strong>(b)</strong> the Employee or the Employee’s Spouse has a Miscarriage; or</p><p><strong>(c)</strong> a child is a Stillborn Child, where the child would have been a member of the Employee’s Immediate Family, or a member of the Employee’s household, if the child had been born alive. Note: An Employee may be entitled to a period of paid special leave if their pregnancy terminates at or after the completion of 20 weeks’ gestation or if the Employee gives birth but the baby subsequently dies – see subclause 70.12(b).</p><p><strong>67.2</strong> If the permissible occasion is the contraction or development of a personal illness, or the sustaining of a personal injury, the Employee may take the compassionate leave for that occasion at any time while the illness or injury persists.</p><p><strong>67.3</strong> Employees other than casual Employees The provisions of subclauses 67.4 to 67.6 apply to all Employees other than casual Employees. The entitlements of casual Employees are set out in subclause 67.7.</p><p><strong>67.4</strong> Subject to the evidence requirements described at subclause 67.8, an Employee is entitled to up to four (4) ordinary days’ paid leave, on each permissible occasion.</p><p><strong>67.5</strong> An Employee may take compassionate leave for a particular permissible occasion as:</p><p><strong>(a)</strong> a single continuous four (4) day period;</p><p><strong>(b)</strong> two (2) separate periods that include at least one (1) single day; or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree (which may include single days).</p><p><strong>67.6</strong> An Employee is additionally entitled to take unpaid leave of up to four (4) days on each permissible occasion. An Employee may take additional unpaid compassionate leave by agreement with the Employer.</p><p><strong>67.7</strong> Casual Employees Subject to the evidence requirements described at subclause 67.8, a casual Employee is entitled to four (4) days unpaid compassionate leave on each permissible occasion. Unpaid compassionate leave under this subclause 67.7 may be taken as:</p><p><strong>(a)</strong> a single continuous period;</p><p><strong>(b)</strong> two (2) separate periods that include at least one (1) single day; or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree (which may include single days).</p><p><strong>67.8</strong> Evidence</p><p>Proof of the injury, illness or death must be provided that would satisfy a reasonable person, if requested.</p><p>Plain language terms: bereavement leave.</p>',22)])])}const u=a(n,[["render",i]]);export{h as __pageData,u as default};
